```class Solution {
public:
    vector<string> removeSubfolders(vector<string>& folder) {
        sort(folder.begin(), folder.end());
        vector<string> res;
        for (int i = 0; i < folder.size(); i++) {
            if (res.empty() || folder[i].substr(0, res.back().size()) != res.back() + "/") {
                res.push_back(folder[i]);
            }
        }
        return res;
    }
};```
